-- Agrega provincia y teléfono al catálogo de registros automotores, y
-- carga masivamente los 835 registros seccionales de AUTOMOTOR (DNRPA) de
-- todo el país. Quedan afuera los de MOTOVEHICULOS y MAQUINARIAS AGRICOLAS
-- (no aplican al negocio de la gestoría).

alter table registros_automotores add column if not exists provincia text;
alter table registros_automotores add column if not exists telefono text;

-- Carga masiva de registros seccionales de AUTOMOTOR (DNRPA), a nivel
-- nacional. Generado a partir del listado oficial provisto por el usuario.

